BASE_SYMBOL_OPTIONS = [
    "EURUSD",
    "GBPUSD",
    "USDJPY",
    "AUDUSD",
    "USDCAD",
    "USDCHF",
    "NZDUSD",
    "EURJPY",
    "GBPJPY",
    "AUDJPY",
    "CADJPY",
    "CHFJPY",
    "NZDJPY",
    "EURGBP",
    "EURCHF",
    "GBPCHF",
    "EURAUD",
    "GBPAUD",
    "EURCAD",
    "GBPCAD",
    "AUDCAD",
    "AUDNZD",
    "EURNZD",
    "GBPNZD",
    "XAUUSD",
    "XAGUSD",
    "US500",
    "NAS100",
    "US30",
]


def get_symbol_options(selected_symbol=None):
    options = list(BASE_SYMBOL_OPTIONS)
    selected = (selected_symbol or "").strip().upper()
    if selected and selected not in options:
        options.insert(0, selected)
    return options


INSTRUMENT_CONTRACT_SIZE = {
    # Metals (common CFD conventions)
    "XAUUSD": 100.0,
    "XAGUSD": 5000.0,
    # Indices (point value per lot; can vary by broker)
    "US500": 1.0,
    "NAS100": 1.0,
    "US30": 1.0,
}


def normalize_symbol(symbol):
    return "".join(ch for ch in (symbol or "").upper() if ch.isalnum())


def is_fx_pair(symbol):
    sym = normalize_symbol(symbol)
    return len(sym) == 6 and sym.isalpha()


def get_contract_size(symbol):
    sym = normalize_symbol(symbol)
    if sym in INSTRUMENT_CONTRACT_SIZE:
        return INSTRUMENT_CONTRACT_SIZE[sym]
    if is_fx_pair(sym):
        return 100000.0
    return 1.0


def quote_to_usd_rate(symbol, reference_price):
    sym = normalize_symbol(symbol)
    if sym.endswith("USD"):
        return 1.0

    # USDXXX pairs can be inverted to convert quote currency to USD.
    if is_fx_pair(sym) and sym.startswith("USD") and reference_price and reference_price > 0:
        return 1.0 / reference_price

    # Crosses like EURJPY need a separate conversion rate (not available here).
    return None


def get_pip_size(symbol):
    sym = normalize_symbol(symbol)
    if not is_fx_pair(sym):
        return None
    return 0.01 if sym.endswith("JPY") else 0.0001


def calc_pips_values(symbol, side, entry_price, exit_price):
    if entry_price is None or exit_price is None:
        return None

    pip_size = get_pip_size(symbol)
    if not pip_size:
        return None

    direction = 1.0 if (side or "").upper() == "BUY" else -1.0
    return direction * ((exit_price - entry_price) / pip_size)


def calc_pnl_values(symbol, side, entry_price, exit_price, lot_size):
    if entry_price is None or exit_price is None:
        return None
    if lot_size is None or lot_size <= 0:
        return None

    direction = 1.0 if (side or "").upper() == "BUY" else -1.0
    contract_size = get_contract_size(symbol)
    conversion_rate = quote_to_usd_rate(symbol, exit_price)
    if conversion_rate is None:
        return None

    return direction * (exit_price - entry_price) * lot_size * contract_size * conversion_rate


def derive_exit_price(symbol, side, entry_price, lot_size, pnl_value):
    if entry_price is None or pnl_value is None:
        return None
    if lot_size is None or lot_size <= 0:
        return None

    direction = 1.0 if (side or "").upper() == "BUY" else -1.0
    contract_size = get_contract_size(symbol)
    units = lot_size * contract_size
    if units <= 0:
        return None

    sym = normalize_symbol(symbol)

    # Quote currency is USD -> linear solve.
    if sym.endswith("USD"):
        return entry_price + (pnl_value / (direction * units))

    # USDXXX nonlinear solve:
    # pnl = direction * (exit-entry) * units / exit
    if is_fx_pair(sym) and sym.startswith("USD"):
        k = pnl_value / (direction * units)
        denom = 1.0 - k
        if abs(denom) < 1e-9:
            return None
        candidate = entry_price / denom
        return candidate if candidate > 0 else None

    return None


def calc_pnl(trade):
    return calc_pnl_values(
        symbol=trade.symbol,
        side=trade.side,
        entry_price=trade.entry_price,
        exit_price=trade.exit_price,
        lot_size=trade.lot_size,
    )


def resolve_pnl(trade):
    if trade.pnl is not None:
        return trade.pnl
    return calc_pnl(trade)


def resolve_pips(trade):
    return calc_pips_values(
        symbol=trade.symbol,
        side=trade.side,
        entry_price=trade.entry_price,
        exit_price=trade.exit_price,
    )


class User(db.Model):
    __tablename__ = "users"

    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(255), nullable=False)
    trades = db.relationship("Trade", backref="user", lazy=True)


class Trade(db.Model):
    __tablename__ = "trades"

    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey("users.id"), nullable=False, index=True)
    symbol = db.Column(db.String(20), nullable=False, default="EURUSD")
    side = db.Column(db.String(10), nullable=False, default="BUY")
    entry_price = db.Column(db.Float, nullable=False, default=0.0)
    exit_price = db.Column(db.Float, nullable=True)
    lot_size = db.Column(db.Float, nullable=False, default=0.01)
    pnl = db.Column(db.Float, nullable=True)
    trade_note = db.Column(db.Text, nullable=True)
    opened_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)


with app.app_context():
    db.create_all()


@app.route("/")
def home():
    if not session.get("user_id"):
        return redirect(url_for("login"))

    username = session.get("username", "User")
    user_id = session["user_id"]

    try:
        user_trades = (
            Trade.query.filter_by(user_id=user_id)
            .order_by(Trade.opened_at.desc())
            .all()
        )
    except OperationalError:
        db.session.rollback()
        user_trades = []

    now = datetime.utcnow()
    week_start = (now - timedelta(days=now.weekday())).replace(
        hour=0, minute=0, second=0, microsecond=0
    )

    closed = []
    for trade in user_trades:
        pnl_value = resolve_pnl(trade)
        if pnl_value is not None:
            closed.append((trade, pnl_value))

    total_closed = len(closed)
    wins = sum(1 for _, pnl in closed if pnl > 0)
    losses = sum(1 for _, pnl in closed if pnl < 0)
    win_rate = (wins / total_closed * 100) if total_closed else 0.0

    net_pnl_week = sum(
        pnl for trade, pnl in closed if trade.opened_at and trade.opened_at >= week_start
    )
    trades_this_month = sum(
        1
        for trade in user_trades
        if trade.opened_at
        and trade.opened_at.month == now.month
        and trade.opened_at.year == now.year
    )

    avg_win = (sum(p for _, p in closed if p > 0) / wins) if wins else 0
    avg_loss = (abs(sum(p for _, p in closed if p < 0)) / losses) if losses else 0
    avg_rr = (avg_win / avg_loss) if avg_loss else None

    recent_trades = []
    for trade in user_trades:
        pnl_value = resolve_pnl(trade)
        pips_value = resolve_pips(trade)
        trade_date = trade.opened_at.strftime("%d %b %Y") if trade.opened_at else "-"
        trade_date_value = trade.opened_at.strftime("%Y-%m-%d") if trade.opened_at else ""
        recent_trades.append(
            {
                "symbol": trade.symbol,
                "side": trade.side,
                "entry_price": trade.entry_price,
                "exit_price": trade.exit_price,
                "lot_size": trade.lot_size,
                "pnl": pnl_value,
                "pips": pips_value,
                "date": trade_date,
                "date_value": trade_date_value,
                "status": "Closed" if trade.exit_price is not None else "Running",
            }
        )

    chart_points = []
    closed_recent = list(reversed(closed[:30]))
    if closed_recent:
        for trade, pnl in closed_recent:
            chart_points.append(
                {
                    "label": trade.opened_at.strftime("%d %b"),
                    "pnl": round(float(pnl), 2),
                }
            )

    return render_template(
        "index.html",
        title="FX Journal",
        username=username,
        win_rate=win_rate,
        net_pnl_week=net_pnl_week,
        trades_this_month=trades_this_month,
        avg_rr=avg_rr,
        recent_trades=recent_trades,
        chart_points=chart_points,
    )


@app.route("/login", methods=["GET", "POST"])
def login():
    if session.get("user_id"):
        return redirect(url_for("home"))

    created = request.args.get("created") == "1"

    if request.method == "POST":
        email = request.form.get("email", "").strip().lower()
        password = request.form.get("password", "")

        user = User.query.filter_by(email=email).first()
        if user and check_password_hash(user.password, password):
            session["user_id"] = user.id
            session["username"] = user.username
            return redirect(url_for("home"))

        return render_template(
            "login.html",
            title="Login | FX Journal",
            body_class="auth-layout",
            error="Invalid email or password.",
            success="Account created. Please log in." if created else None,
        )
    return render_template(
        "login.html",
        title="Login | FX Journal",
        body_class="auth-layout",
        success="Account created. Please log in." if created else None,
    )


@app.route("/register", methods=["GET", "POST"])
def register():
    if session.get("user_id"):
        return redirect(url_for("home"))

    if request.method == "POST":
        username = request.form.get("username", "").strip()
        email = request.form.get("email", "").strip().lower()
        password = request.form.get("password", "")

        if not username or not email or not password:
            return render_template(
                "register.html",
                title="Register | FX Journal",
                body_class="auth-layout",
                error="All fields are required.",
            )

        existing_user = User.query.filter(
            or_(User.username == username, User.email == email)
        ).first()
        if existing_user:
            return render_template(
                "register.html",
                title="Register | FX Journal",
                body_class="auth-layout",
                error="Username or email already exists.",
            )

        hashed_password = generate_password_hash(password)
        user = User(username=username, email=email, password=hashed_password)
        db.session.add(user)
        db.session.commit()
        return redirect(url_for("login", created="1"))

    return render_template(
        "register.html",
        title="Register | FX Journal",
        body_class="auth-layout",
    )


@app.route("/logout", methods=["POST"])
def logout():
    session.clear()
    return redirect(url_for("login"))

